<?php if ( ! defined( 'ABSPATH' ) ) exit; global $wpdb; $pools=$wpdb->get_results('SELECT id,name FROM '.qm2026_table('pools').' ORDER BY name'); ?>
<div class="wrap qm2026"><h1><?php esc_html_e('Importar / Exportar',QM2026_TEXT_DOMAIN); ?></h1><?php if(!empty($_GET['qm2026_notice'])) echo '<div class="notice notice-success"><p>'.esc_html(wp_unslash($_GET['qm2026_notice'])).'</p></div>'; ?><div class="qm2026-grid"><form class="qm2026-card" method="post" enctype="multipart/form-data"><?php wp_nonce_field('qm2026_admin_action'); ?><input type="hidden" name="qm2026_action" value="import_fixture"><h2><?php esc_html_e('Importar partidos JSON',QM2026_TEXT_DOMAIN); ?></h2><input type="file" name="fixture" accept="application/json" required><p><button class="button button-primary"><?php esc_html_e('Importar fixture',QM2026_TEXT_DOMAIN); ?></button></p></form><div class="qm2026-card"><h2><?php esc_html_e('Exportar CSV',QM2026_TEXT_DOMAIN); ?></h2><p><a class="button" href="<?php echo esc_url(wp_nonce_url(admin_url('admin.php?page=qm2026-import-export&qm2026_export_participants=1'),'qm2026_export_participants')); ?>"><?php esc_html_e('Participantes',QM2026_TEXT_DOMAIN); ?></a></p><p><a class="button" href="<?php echo esc_url(wp_nonce_url(admin_url('admin.php?page=qm2026-import-export&qm2026_export_predictions=1'),'qm2026_export_predictions')); ?>"><?php esc_html_e('Predicciones',QM2026_TEXT_DOMAIN); ?></a></p><h2><?php esc_html_e('Exportar ranking CSV',QM2026_TEXT_DOMAIN); ?></h2><?php foreach($pools as $pool): ?><p><a class="button" href="<?php echo esc_url(wp_nonce_url(admin_url('admin.php?page=qm2026-import-export&qm2026_export_ranking=1&pool_id='.$pool->id),'qm2026_export_ranking')); ?>"><?php echo esc_html($pool->name); ?></a></p><?php endforeach; ?></div></div><p><a href="<?php echo esc_url(QM2026_URL.'assets/data/fixture-2026.json'); ?>" target="_blank"><?php esc_html_e('Descargar example-fixture.json',QM2026_TEXT_DOMAIN); ?></a></p></div>
